import { test, expect } from '@playwright/test';
import * as fs from 'fs';
import * as path from 'path';

test('Check dashboard for 500 errors after fix', async ({ page }) => {
  // Collect all failed network requests (4xx and 5xx)
  const failedRequests: { url: string; status: number; method: string; statusText: string }[] = [];

  page.on('response', (response) => {
    const status = response.status();
    if (status >= 400) {
      failedRequests.push({
        url: response.url(),
        status: status,
        method: response.request().method(),
        statusText: response.statusText(),
      });
    }
  });

  // Also capture request failures (network errors, etc.)
  const networkErrors: { url: string; error: string }[] = [];
  page.on('requestfailed', (request) => {
    networkErrors.push({
      url: request.url(),
      error: request.failure()?.errorText || 'Unknown error',
    });
  });

  // Step 1: Go to the login page
  console.log('Navigating to login page...');
  await page.goto('https://nexus-ai-silk-six.vercel.app/login', { waitUntil: 'networkidle' });
  console.log('Login page loaded.');

  // Step 2: Fill in login credentials
  console.log('Filling login form...');
  await page.fill('input[type="email"], input[name="email"], input[placeholder*="email" i]', 'testuser@nexusai-test.com');
  await page.fill('input[type="password"], input[name="password"], input[placeholder*="password" i]', 'TestPassword123!');

  // Click the login/submit button
  await page.click('button[type="submit"], button:has-text("Sign in"), button:has-text("Log in"), button:has-text("Login"), button:has-text("Se connecter")');
  console.log('Login form submitted.');

  // Step 3: Wait for redirect to /dashboard
  console.log('Waiting for redirect to dashboard...');
  try {
    await page.waitForURL('**/dashboard**', { timeout: 15000 });
    console.log('Redirected to dashboard: ' + page.url());
  } catch (e) {
    console.log('Warning: Did not redirect to /dashboard within timeout. Current URL: ' + page.url());
    // Take a screenshot of wherever we ended up
  }

  // Step 4 & 5: Wait 5 seconds for all network requests to complete
  console.log('Waiting 5 seconds for all requests to complete...');
  await page.waitForTimeout(5000);

  // Also wait for network idle
  try {
    await page.waitForLoadState('networkidle', { timeout: 10000 });
  } catch (e) {
    console.log('Warning: Network did not become idle within timeout.');
  }

  // Step 6: Take screenshot
  const screenshotDir = 'C:\\Users\\User\\nexus-ai\\test-screenshots';
  const screenshotPath = path.join(screenshotDir, '08-dashboard-after-fix.png');

  // Ensure directory exists
  if (!fs.existsSync(screenshotDir)) {
    fs.mkdirSync(screenshotDir, { recursive: true });
  }

  await page.screenshot({ path: screenshotPath, fullPage: true });
  console.log('Screenshot saved to: ' + screenshotPath);

  // Step 7: Report results
  console.log('\n========== NETWORK ERROR REPORT ==========');
  console.log(`Current URL: ${page.url()}`);
  console.log(`Total failed requests (4xx/5xx): ${failedRequests.length}`);

  const errors500 = failedRequests.filter(r => r.status >= 500);
  const errors4xx = failedRequests.filter(r => r.status >= 400 && r.status < 500);

  console.log(`  - 5xx errors: ${errors500.length}`);
  console.log(`  - 4xx errors: ${errors4xx.length}`);
  console.log(`Network failures: ${networkErrors.length}`);

  if (errors500.length > 0) {
    console.log('\n--- 5xx ERRORS ---');
    errors500.forEach((r, i) => {
      console.log(`  ${i + 1}. [${r.status}] ${r.method} ${r.url}`);
    });
  }

  if (errors4xx.length > 0) {
    console.log('\n--- 4xx ERRORS ---');
    errors4xx.forEach((r, i) => {
      console.log(`  ${i + 1}. [${r.status}] ${r.method} ${r.url}`);
    });
  }

  if (networkErrors.length > 0) {
    console.log('\n--- NETWORK FAILURES ---');
    networkErrors.forEach((r, i) => {
      console.log(`  ${i + 1}. ${r.url} - ${r.error}`);
    });
  }

  // Save report to file
  const report = {
    timestamp: new Date().toISOString(),
    currentUrl: page.url(),
    summary: {
      total4xx: errors4xx.length,
      total5xx: errors500.length,
      totalNetworkFailures: networkErrors.length,
    },
    errors5xx: errors500,
    errors4xx: errors4xx,
    networkFailures: networkErrors,
  };

  const reportPath = path.join(screenshotDir, '08-dashboard-error-report.json');
  fs.writeFileSync(reportPath, JSON.stringify(report, null, 2));
  console.log(`\nReport saved to: ${reportPath}`);

  console.log('\n========== END REPORT ==========');

  // The test passes regardless - we are gathering data
  // But log a clear verdict
  if (errors500.length === 0) {
    console.log('\n✅ VERDICT: No 500 errors detected on the dashboard!');
  } else {
    console.log(`\n❌ VERDICT: ${errors500.length} 500 error(s) still present on the dashboard.`);
  }
});
